import java.util.concurrent.CompletableFuture;

class Fanout {
  static CompletableFuture<String> loadUser(String userId) {
    return CompletableFuture.completedFuture(userId + ":user");
  }

  static CompletableFuture<String> loadProfile(String userId) {
    return CompletableFuture.completedFuture(userId + ":profile");
  }

  static String merge(String user, String profile) {
    return user + "|" + profile;
  }

  static String app(String userId) {
    CompletableFuture<Void> both = CompletableFuture.allOf(
        loadUser(userId),
        loadProfile(userId));
    both.join();
    return merge(userId + ":user", userId + ":profile");
  }

  public static void main(String[] args) {
    String inputJson = args.length > 0 ? args[0] : "{\"userId\":\"ada\"}";
    String userId = inputJson
        .replaceAll(".*\\\"userId\\\"\\s*:\\s*\\\"([^\\\"]+)\\\".*", "$1");
    System.out.println(app(userId));
  }
}
